#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int age;
        char country[25];
        scanf("%d %24s", &age, country);
        if (age >= 18 && strcmp(country, "India") == 0) {
            printf("Eligible\n");
        } else {
            printf("Not Eligible\n");
        }
    }
    return 0;
}

